public class Main {
    // Custom input reader class to handle input operations efficiently
    private static class InputReader {
        private InputStream stream; // Input stream to read data from
        private byte[] buf = new byte[1024]; // Buffer to store input data
        private int curChar; // Current character index in the buffer
        private int numChars; // Number of characters read into the buffer
        private SpaceCharFilter filter; // Optional filter to determine space characters

        // Constructor to initialize the input reader with an input stream
        public InputReader(InputStream stream) {
            this.stream = stream;
        }

        // Method to read the next byte of data from the input stream
        public int read() {
            if (numChars == -1) {
                throw new InputMismatchException(); // Throw exception if end of stream is reached
            }
            if (curChar >= numChars) {
                curChar = 0;
                try {
                    numChars = stream.read(buf); // Read data into buffer
                } catch (IOException e) {
                    throw new InputMismatchException(); // Throw exception on I/O error
                }
                if (numChars <= 0) {
                    return -1; // Return -1 if no more data is available
                }
            }
            return buf[curChar++]; // Return the next byte from the buffer
        }

        // Method to read an integer from the input
        public int readInt() {
            int c = read();
            while (isSpaceChar(c)) {
                c = read(); // Skip space characters
            }
            int sgn = 1; // Sign of the number
            if (c == '-') {
                sgn = -1; // Negative number
                c = read();
            }
            int res = 0; // Resulting integer
            do {
                if (c < '0' || c > '9') {
                    throw new InputMismatchException(); // Throw exception if not a digit
                }
                res *= 10;
                res += c - '0'; // Convert character to integer
                c = read();
            } while (!isSpaceChar(c)); // Continue until a space character is found
            return res * sgn; // Return the integer with the correct sign
        }

