            a[i] = saori.saori_hayami();
        }

        // Read n elements into array b
        for(int i = 0; i < n; i++){
            b[i] = saori.saori_hayami();
        }

        // Variable to store the final answer
        long ans = 0;

        // Iterate over each element to calculate the result
        for(int i = 0; i < n; i++){
            if(a[i] >= b[i]){
                // If a[i] is greater than or equal to b[i], add b[i] to ans
                ans += b[i];
            } else {
